const input = $input.first().json;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.ntfy&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;

if (!creds.ntfy_topic) {
  return [{ json: { error: 'ntfy topic not configured. Use add_credential to set "ntfy_topic" (your private topic name, e.g. claw-alerts-ab3f9d21xy).' } }];
}

const serverUrl = (creds.ntfy_server_url || 'https://ntfy.sh').replace(/\/+$/, '');
const topic = creds.ntfy_topic.replace(/^\/+|\/+$/g, '');
const url = serverUrl + '/' + topic;

const message = input.message;
if (!message) return [{ json: { error: 'Parameter "message" is required (the notification body text).' } }];

// RFC 2047 header encoding for non-ASCII (emoji, umlauts) — HTTP headers are ASCII-only
function encodeHeader(val) {
  const s = String(val);
  if (/^[\x00-\x7F]*$/.test(s)) return s;
  return '=?utf-8?B?' + Buffer.from(s, 'utf8').toString('base64') + '?=';
}

const headers = { 'Content-Type': 'text/plain; charset=utf-8' };
if (creds.ntfy_token) headers['Authorization'] = 'Bearer ' + creds.ntfy_token;

if (input.title) headers['Title'] = encodeHeader(input.title);
if (input.priority) {
  const p = parseInt(input.priority);
  if (p >= 1 && p <= 5) headers['Priority'] = String(p);
}
if (input.tags) {
  const tags = Array.isArray(input.tags) ? input.tags.join(',') : String(input.tags);
  headers['Tags'] = encodeHeader(tags);
}
if (input.click) headers['Click'] = String(input.click);
if (input.attach) {
  headers['Attach'] = String(input.attach);
  if (input.filename) headers['Filename'] = encodeHeader(input.filename);
}

function serializeError(e) {
  if (!e) return 'unknown error';
  if (typeof e === 'string') return e;
  if (typeof e.message === 'string' && e.message.length > 0) return e.message;
  if (e.response) {
    const sc = e.response.statusCode || e.response.status || '?';
    const body = e.response.body || e.response.data || e.response.message;
    const bodyStr = typeof body === 'string' ? body : (body ? JSON.stringify(body) : '');
    return 'HTTP ' + sc + (bodyStr ? ': ' + bodyStr : '');
  }
  try { return JSON.stringify(e); } catch (_) { return String(e); }
}

try {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: headers,
    body: String(message)
  });
  let summary = 'Notification sent to topic "' + topic + '"';
  if (resp && resp.id) summary += ' (id: ' + resp.id + ')';
  if (input.title) summary += '\nTitle: ' + input.title;
  summary += '\nMessage: ' + message;
  if (resp && resp.attachment && resp.attachment.url) summary += '\nAttachment: ' + resp.attachment.url;
  return [{ json: { result: summary } }];
} catch (e) {
  let msg = serializeError(e);
  if (msg.includes('403') || msg.includes('401')) {
    msg = 'Access denied. This topic may be reserved — configure ntfy_token with a valid access token. Original: ' + msg;
  } else if (msg.includes('429')) {
    msg = 'Rate limited. ntfy.sh free tier allows limited messages per hour per IP. Original: ' + msg;
  }
  return [{ json: { error: 'Failed to send notification: ' + msg } }];
}
